module RefModule(clock, reset, wren, data, q);input clock, reset, wren;
	input  [31:0] data;
	output reg [31:0] q;


	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clock or posedge dbg_halt)
	if (reset==1'b1)
		q = 32'b0;
	else if(wren == 1'b1)
		q = data;

endmodule
